var e=JSON.parse(`[{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"으음, 이게 무슨 소리지?","JPN":"うん？　これは何の音？","ENG":"Mm... What's that noise?","TWN":"呃嗯，這是什麼聲音？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L9_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"오래 기다리셨습니다. 학생 여러분.","JPN":"生徒の皆様、お待たせいたしました。","ENG":"Dear students, thank you for your patience.","TWN":"同學們，大家久等了。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L10_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"조화와 화합의 학원제, 애쉬포드 학원제가 내일로 다가왔습니다. 모두 후회없는 축제 준비를 부탁드리겠습니다.","JPN":"いよいよ調和と和合の学園祭、アッシュフォード学園祭が明日へと迫りました。\\n皆さん、悔いのないように準備をお願いします。","ENG":"Tomorrow is the Harmony and Balance Festival at Ashford Academy. I hope everyone makes every effort to prepare for the festival.","TWN":"明天就是全校同歡的阿什弗德學園祭，請大家做足準備，不要留下遺憾。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"회장? 어제도 이거랑 비슷한 일이 있지 않았나?","JPN":"会長？　っていうか、昨日も同じようなことがあったような？","ENG":"Yen? Didn't she say something similar yesterday?","TWN":"會長？昨天不是也說過一樣的話嗎？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"분명, 이 다음에 나이엘이…….","JPN":"確か、この後ナイエルが……","ENG":"And right after, Naielle says...","TWN":"接下來奈爾就會……"},"stage":{"bg":"GEASS_ASHFORD","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"으으, 못하겠어! 못하겠다구!! 전교생이 듣는데 부끄럽게 그걸 어떻게 해!?","JPN":"うう、やっぱりできない！　できないわよ！\\n全校生徒の前でこんな恥ずかしいことできるわけないでしょ！","ENG":"Bah! I can't do it! I just can't!! How can I say that in front of everybody without getting embarrassed?!","TWN":"唉唷，我不行啦！我做不到！！全校學生都會聽到欸，那麼害羞，我沒辦法啦！"},"stage":{"bg":"SKY","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"뭐야, 지금 건? 전야제 준비 방송인가?","JPN":"なんだ、今の？　前夜祭の準備放送か？","ENG":"Huh? What was that? Was that the rehearsal broadcast for tomorrow's festival?","TWN":"剛那是怎樣？是在彩排嗎？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"뭐, 평소대로의 학생회 같은 분위기잖아? 내일 학원제가 기대되는 걸?","JPN":"ふふっ。でも、生徒会らしいじゃない。明日の学園祭が楽しみね。","ENG":"Well, it's just any other day for the Student Council. Anyway, I'm hyped about tomorrow's festival!","TWN":"不是學生會的日常發揮嗎？真期待明天的學園祭。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"잠깐, 대체 뭐가 어떻게 돌아가는 거야? 분명 어제도……","JPN":"いや、いったい何がどうなっているの？　確か昨日も……","ENG":"Wait a minute. What's going on? This all happened yesterday...","TWN":"等等，現在到底是什麼情況？明明昨天就……"},"stage":{"bg":"GEASS_ASHFORD","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어제? 가만, 어제 무슨 일이 있었더라?","JPN":"昨日？　ん？　昨日何かあったっけ？","ENG":"Yesterday? Huh? What happened yesterday?","TWN":"昨天？等等，昨天發生了什麼事？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_QM","text":{"KOREA":"미나야!","JPN":"ミナ！","ENG":"Mina!","TWN":"米娜！"},"stage":{"bg":"GEASS_ASHFORD","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_QM","text":{"KOREA":"정말! 이런 곳에서 뭘 하고 있어! 다들 널 얼마나 찾았는데!","JPN":"もう！　こんなところで何してるの？　みんな探してたんだよ！","ENG":"Seriously? What are you doing here? Everyone's been looking all over for you!","TWN":"真是的！你在這裡做什麼！大家都在找你！"},"stage":{"bg":"GEASS_ASHFORD","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_QM","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어, 너는? 그러니까, 셜리였던가?","JPN":"あ、あなたは？　えっと、シャーリーだったっけ？","ENG":"Huh? You're…? Uh, Shirley, right?","TWN":"喔！你是？你是夏麗嗎？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_QM","face":"UNIT_SERIOUS"}}}},{"id":"L33_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"뭐어? 미나, 설마 내 이름 잊어버린 거야?","JPN":"ええっ？！　ミナ、まさか私の名前を忘れたの？","ENG":"Huh? Mina, did you forget my name?","TWN":"什麼？米娜，你忘記我的名字了嗎？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아, 아니 그런 건 아닌데 왠지 엄청 오랜만에 보는 것 같아서.","JPN":"いや、そういうわけじゃないけど、\\nなんだかとても久しぶりに会った気がしてね。","ENG":"N-no, it just felt like I haven't seen you in a long time.","TWN":"不，不是啦，我沒忘，只是有種好久不見的感覺。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L35_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"우리 어제도 봤잖아? 이상하네. 아니면 그새 보고 싶었던 거야?","JPN":"私たち昨日も会ったでしょ？\\n変なの。それとも、そんなに私に会いたかったのかな？","ENG":"But we saw each other yesterday. Strange. Or did you miss me that much?","TWN":"我們昨天不是也有見面嗎？你這麼快就想我啦？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"으, 으응. 그런가…….","JPN":"う、うん。そうだね……","ENG":"Y-yeah... I think that's it...","TWN":"呃，嗯，是這樣嗎……"},"stage":{"bg":"GEASS_ASHFORD","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"기쁘긴 한데. 어쨌든 빨리 학생회실로 돌아가자. 이러다 회의 늦겠어.","JPN":"それは嬉しいけどさ。\\n今ははやく生徒会室に行こう。会議に遅れちゃうよ。","ENG":"I'm flattered, but we need to get to the Student Council office. We're gonna be late for the meeting.","TWN":"我是很開心啦，但我們還是先回去學生會辦公室吧，快遲到啦。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"학생회실? 아아, 나는 학생회 임원이고…… 그래서 학원제 준비를……. 응?","JPN":"生徒会室？　ああ、私は生徒会役員だから……\\n学園祭の準備を進めなきゃ……、あれ？","ENG":"The Student Council office? Oh, I'm a Student Council member... and I need to help with the festival prep... hmm?","TWN":"學生會辦公室？喔喔～我是學生會幹部……要準備學園祭……嗯？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"잠깐! 셜리, 학원제는 오늘부터 시작이잖아?","JPN":"まって、シャーリー！　学園祭って今日からだよね？","ENG":"Wait! Shirley, doesn't the festival start today?","TWN":"夏麗，我問你，學園祭是今天開始吧？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"무슨 소리야, 학원제는 내일부터 시작인 걸?","JPN":"何を言ってるの、学園祭は明日からだよ？","ENG":"What are you talking about? It starts tomorrow.","TWN":"你在說什麼？學園祭是明天開始。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"내일이라고……?","JPN":"明日って……？","ENG":"Tomorrow...?","TWN":"明天開始……？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"확실히…… 그랬던 것 같기도 하고……?","JPN":"確かに……そんな気もするけど……","ENG":"Now that I think about it... I think that's right...?","TWN":"好像……確實是那樣……？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"정말, 학원제 준비가 힘들다고 해도, 현실도피는 안 된다구!","JPN":"準備が大変だからって、現実逃避しちゃダメだよ？","ENG":"C'mon, I know it's a lot of work getting everything prepared, but it's not healthy to escape from reality!","TWN":"真是的，我知道預備學園祭很辛苦，但也不能逃避現實吧！"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L48_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"하, 하하. 그런가?","JPN":"はは……は……そうかな？","ENG":"H-ha ha. You're right.","TWN":"哈，哈哈，是嗎？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L49_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"아무튼 서두르자. 모두 미나를 기다리고 있어.","JPN":"とにかく急ごう。みんなミナのことを待ってるよ。","ENG":"Anyway, let's hurry. They're all waiting for you, Mina.","TWN":"總之動作快，大家都在等你。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_LAUGH"}}}},{"id":"L50_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"……응.","JPN":"……うん。","ENG":"...Okay.","TWN":"……嗯。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"우선, 실행위원장으로서 내일 학원제의 준비 상황을 보고하자면……","JPN":"さて、まずは学園祭実行委員長の俺から明日に控えた学園祭の進捗状況を報告する。","ENG":"First and foremost, as the head of the executive committee, I'll report on the status of preparations for tomorrow's festival...","TWN":"首先，就由身為執行委員長的我，來跟大家報告學園祭的準備情形……"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"전체적으로는 순조로운 편이지만, 현재 몇몇 동아리로부터 클레임이 접수된 상태야.","JPN":"全体的には順調だが、いくつか苦情やトラブルの報告が寄せられている。","ENG":"Everything is going smoothly overall, but a few clubs have filed some complaints.","TWN":"整體而言是順利的，只是有幾個社團提出一些訴求。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그렇군요. 임원들이 각각 분담해서 해결하면 좋겠네요.","JPN":"なるほど。役員で各トラブルを分担して解決を図りましょうか。","ENG":"I see. The members can each take charge of one and resolve the issues.","TWN":"是嗎？那就由幹部們一起分頭處理吧。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"먼저 수영부에서 클레임을 보내왔어.","JPN":"まずは、水泳部からの苦情だな。","ENG":"First, from the swim club.","TWN":"首先是游泳部的訴求。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"수영부에서는 카페를 준비하고 있는데, 카페 주변에서 원인 모를 악취가……","JPN":"水泳部はカフェを準備しているが、どこからか原因不明の悪臭がして……","ENG":"They are preparing to open a cafe, but they keep smelling this awful–","TWN":"他們表示，游泳部在籌備開設咖啡廳，但咖啡廳周圍卻發出不明惡……"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"잠깐, 를르슈!","JPN":"待って、ルルーシュ！","ENG":"Hold on, Lelouch!","TWN":"等一下，魯路修！"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"왜 그러지, 미나?","JPN":"どうしたんだ、ミナ？","ENG":"What is it, Mina?","TWN":"怎麼了，米娜？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"수영장에서 악취가 나는 이유…… 나, 알고 있을지도 몰라.","JPN":"プールの悪臭の原因……私、知ってるかも。","ENG":"I think I know... where the smell is coming from at the pool.","TWN":"游泳池發出惡臭的原因……我好像知道。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"수영부실 근처에 기름통이 있었어. 아마 악취의 원인은 그 기름통 때문일 거야.","JPN":"水泳部の部室の近くに油缶が置いてあるの。おそらく悪臭の原因はその缶のせいだと思う。","ENG":"There's an oil barrel near the clubroom. I think that's the source of the stench.","TWN":"游泳部社辦附近有汽油桶，那就是惡臭的來源。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"뭐야, 너? 어떻게 그런 걸 알고 있는 거야?","JPN":"なによあんた。なんでそんなことがわかるの？","ENG":"Huh? How do you know that?","TWN":"哇賽？你是怎麼知道的？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그건…… 나도 잘 모르겠어. 어쩐지 그럴 것 같은 느낌이 들어.","JPN":"それは……私にもよくわからない。ただ、なんとなくそんな気がして。","ENG":"That's... I have no idea. I just have a feeling.","TWN":"這個……我也不清楚，但就覺得是那樣。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"어쩐지 그럴 것 같다고? 그게 무슨 잠꼬대 같은 소리야?","JPN":"は？　なんとなく？　寝ぼけてんの？","ENG":"You have a feeling? What's that supposed to mean?","TWN":"就覺得是那樣？你的發言毫無根據嗎？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"흐음, 글쎄? 그냥 무시하기에는 꽤 구체적인데?","JPN":"ふむ。しかし、ミナの話も聞き流すには内容がかなり鮮明だ。","ENG":"Hmm, who knows? But it's too specific to just ignore it, no?","TWN":"嗯，這個嘛？但米娜又說得那麼具體。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"셜리, 수영부에 연락해서 부실 근처에 미나가 말한 기름통이 있는지 확인해주겠어?","JPN":"シャーリー、水泳部に連絡して\\n部室の付近にミナが言っていた油缶があるか確かめてくれないか？","ENG":"Shirley, will you contact the swim club and ask if they see an oil barrel nearby, please?","TWN":"夏麗，你聯絡一下游泳部，請他們確認一下社辦附近有沒有汽油桶。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"루루! 정말이었어! 미나 말대로 부실 근처에 기름통이 있었나 봐!","JPN":"ルル！　本当だったよ！\\nミナの言ってたとおり、部室の近くに油缶があったみたい！","ENG":"Lulu! It's true! There was an oil barrel, just like Mina said!","TWN":"魯魯！真的有欸！就像米娜說的那樣，附近好像有汽油桶！"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"대단하네, 미나! 대체 어떻게 알아낸 거야?","JPN":"すごいねミナ。どうしてわかったの？","ENG":"Incredible, Mina! How did you know about that?","TWN":"你好厲害喔，米娜！你到底是什麼知道的？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"그렇네. 우연히 기름통을 봤다고 해도, 보통은 그냥 지나쳤을 텐데. 기억력이 좋은데?","JPN":"そうね。偶然見かけたとしても普通は憶えてないわ。\\n記憶力がいいのね。","ENG":"Yeah. Normally, people wouldn't think much of a random barrel lying around. You've got a pretty good memory, don't you?","TWN":"對啊，就算是路過碰巧看到，一般人都不會放在心上吧？你記性很好欸。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"하하…… 글쎄? 나도 갑자기 떠올랐을 뿐이라서.","JPN":"はは……、どうしてだろ。\\n私も偶然思い出しただけだから……","ENG":"Hah hah... I guess? It just popped into my mind.","TWN":"哈哈……不知道欸？我也是突然想到的。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"잠깐! 뭔가 이상하잖아? 너 뭔가 수영부랑 짜고 치는 거 아니야?","JPN":"待って！　怪しいと思うのは私だけ？\\nあんた、水泳部とグルになって自分で仕込んだんじゃないの？","ENG":"Hold it! I smell something fishy here. You plotted this whole thing with the swim club, didn't you?","TWN":"等等！不覺得很奇怪嗎？你該不會是和游泳部串通好的吧？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"무슨 소리야, 나이엘. 미나가 그런 짓을 해서 무슨 득을 본다는 거야?","JPN":"言いがかりはよせ、ナイエル。\\nミナがそんなことをして何の得があるというんだ？","ENG":"That makes no sense, Naielle. What would Mina get out of doing something like that?","TWN":"奈爾，你在胡說什麼？米娜這麼做有什麼好處？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L42_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"흥! 그야 뻔하잖아? 알량한 방법으로 다른 애들한테 인기 좀 끌어보려는 거겠지!","JPN":"ふん！　そりゃあこいつのことだもの！\\nズルをして他の生徒から注目を浴びたいだけなんじゃない？","ENG":"Hmph! It's obvious! She's trying to get popular among the other kids!","TWN":"哼！這不是很明顯嗎？他想用這種小伎倆拉抬自己的人氣！"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L43_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"그래봤자, 올해 학원제의 주인공은 이 나이엘 님이지만 말이야!","JPN":"そんなことをしたところで、今年の学園祭の主役はこのナイエル様なんだけどね！","ENG":"But it's useless. Because the star of this year's festival is me, Naielle!","TWN":"但是沒用的啦！今年學園祭的主角一定是我！"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그러고보니 나이엘 양, 후야제에서 피울 캠프파이어 준비는 어떻게 되어가고 있죠?","JPN":"主役といえば、ナイエルさん。\\n後夜祭のメインとなるキャンプファイヤーの準備の進捗はいかがですか？","ENG":"Speaking of which, Naielle. How are the preparations for the post-festival party's campfire going?","TWN":"話說回來，奈爾，慶功宴要用的營火預備得怎麼樣？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"에, 에엑……? 올해의 캠프파이어 담당이 나라고?","JPN":"え、ええっ！？　今年のキャンプファイヤー担当が私ですって！？","ENG":"E-eck...? Is that supposed to be my duty?","TWN":"欸欸欸……？今年是我負責升營火喔？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"……그럼 각자 맡은 일이 끝난 뒤 캠프파이어 준비를 돕도록 하죠.","JPN":"……それでは、各自担当の仕事が終わったら\\nキャンプファイヤーの準備を手伝うことにしましょう。","ENG":"...Then, after we are all done with our tasks, let's help the two out with the campfire preparations.","TWN":"那就各自忙完交付的任務後，再一起協助準備營火。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"미나 양? 아까부터 말씀이 없으시네요. 괜찮으세요?","JPN":"ミナさん？　さっきから静かですね、大丈夫ですか？","ENG":"Mina? You haven't said a word. Are you okay?","TWN":"米娜？你怎麼都不說話？還好嗎？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아, 미안. 잠깐 딴 생각을 했네.","JPN":"あ、ごめん。ちょっと違うことを考えてた","ENG":"Oh, sorry. I guess I zoned out again.","TWN":"喔，抱歉，我剛在想別的事。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그보다 나는 뭘 도우면 될까?","JPN":"それより、私は何を手伝えばいい？","ENG":"Anyway, is there something I can help with?","TWN":"那我要幫什麼忙呢？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"으음, 그럼 미나 카렌과 사진부를 도와줄 수 있겠어?","JPN":"ふむ、ではミナ。カレンと一緒に写真部の件を任せていいかな？","ENG":"Hmm, then could you go with Kallen and help out the photography club?","TWN":"那米娜可以幫忙卡蓮和攝影部嗎？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"응, 사진부를 도우면 되는 거지? 알겠어.","JPN":"写真部ね、わかった。","ENG":"Sure. The photography club, right? Got it.","TWN":"嗯，協助攝影部就好嗎？好的。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};